#include <bits/stdc++.h>
using namespace std;
int main(){
    int a,b;
    cin>>a>>b;
    int n[a];
    for (int j=0;j<a;j++) n[j]=-1;
    int p=0,x,z=0;
    for(int i=0;i<b;i++){
        cin>>x;
        int l=0;
        for(int j=0;j<a;j++){
            if(n[j]==x){
                l=1;
                break;
            }
        }
        if(l==0){
            z++;
            n[p]=x;
            p=(p+1)%a;
        }
    }
    cout<<z;
    return 0;
}
